import * as React from "react";
import { cn } from "../lib/cn";

export type ToastTone = "neutral" | "accent" | "danger" | "warning" | "info";

export type ToastProps = React.HTMLAttributes<HTMLDivElement> & {
  action?: React.ReactNode;
  description?: React.ReactNode;
  onDismiss?: () => void;
  title: React.ReactNode;
  tone?: ToastTone;
};

const toastToneStyles: Record<ToastTone, string> = {
  neutral: "border-axie-line bg-axie-surface",
  accent: "border-axie-accent/26 bg-axie-accent-soft",
  danger: "border-axie-danger/26 bg-axie-danger-soft",
  warning: "border-axie-warning/28 bg-axie-warning-soft",
  info: "border-axie-info/26 bg-axie-info-soft"
};

export function Toast({
  action,
  className,
  description,
  onDismiss,
  title,
  tone = "neutral",
  ...props
}: ToastProps) {
  return (
    <div
      className={cn(
        "grid min-w-0 gap-3 rounded-axie-card border p-axie-md text-axie-ink shadow-[0_18px_42px_color-mix(in_srgb,var(--axie-color-ink)_10%,transparent)] axie-enter sm:grid-cols-[minmax(0,1fr)_auto] sm:items-start",
        toastToneStyles[tone],
        className
      )}
      role="status"
      {...props}
    >
      <div className="grid min-w-0 gap-1">
        <p className="m-0 text-[14px] font-black leading-5">{title}</p>
        {description ? (
          <p className="m-0 text-[13px] font-bold leading-5 text-axie-muted">{description}</p>
        ) : null}
      </div>
      {action || onDismiss ? (
        <div className="flex shrink-0 items-start gap-2">
          {action ? <div>{action}</div> : null}
          {onDismiss ? (
            <button
              aria-label="Dismiss toast"
              className="grid h-7 w-7 place-items-center rounded-[8px] border border-axie-line bg-axie-surface/70 text-[12px] font-black text-axie-muted transition hover:border-axie-muted/42 hover:text-axie-ink"
              type="button"
              onClick={onDismiss}
            >
              x
            </button>
          ) : null}
        </div>
      ) : null}
    </div>
  );
}

export type ToastStackProps = React.HTMLAttributes<HTMLDivElement> & {
  position?: "top-right" | "bottom-right" | "bottom-left";
};

const toastStackPositions: Record<NonNullable<ToastStackProps["position"]>, string> = {
  "bottom-left": "bottom-4 left-4",
  "bottom-right": "bottom-4 right-4",
  "top-right": "right-4 top-4"
};

export function ToastStack({
  className,
  position = "bottom-right",
  ...props
}: ToastStackProps) {
  return (
    <div
      className={cn(
        "fixed z-40 grid w-[min(380px,calc(100vw-32px))] gap-2",
        toastStackPositions[position],
        className
      )}
      {...props}
    />
  );
}

"use client";

import * as React from "react";
import { createPortal } from "react-dom";
import { Toast, ToastStack, type ToastProps, type ToastStackProps } from "./toast";

export type ToastOptions = Omit<ToastProps, "id" | "onDismiss"> & {
  duration?: number;
  id?: string;
};

type ActiveToast = ToastOptions & {
  duration: number;
  id: string;
};

type ToastContextValue = {
  dismiss: (id: string) => void;
  toast: (options: ToastOptions) => string;
  toasts: ActiveToast[];
};

const ToastContext = React.createContext<ToastContextValue | null>(null);
let toastId = 0;

export type ToastProviderProps = {
  children: React.ReactNode;
  limit?: number;
  position?: ToastStackProps["position"];
};

export function ToastProvider({
  children,
  limit = 4,
  position = "bottom-right"
}: ToastProviderProps) {
  const [mounted, setMounted] = React.useState(false);
  const [toasts, setToasts] = React.useState<ActiveToast[]>([]);
  const timeouts = React.useRef(new Map<string, number>());

  const dismiss = React.useCallback((id: string) => {
    const timeout = timeouts.current.get(id);
    if (timeout) window.clearTimeout(timeout);
    timeouts.current.delete(id);
    setToasts((current) => current.filter((toast) => toast.id !== id));
  }, []);

  const toast = React.useCallback(
    (options: ToastOptions) => {
      const id = options.id ?? `toast-${++toastId}`;
      const duration = options.duration ?? 4200;
      const nextToast: ActiveToast = { ...options, duration, id };

      setToasts((current) => [...current.filter((item) => item.id !== id), nextToast].slice(-limit));

      const existingTimeout = timeouts.current.get(id);
      if (existingTimeout) window.clearTimeout(existingTimeout);

      if (duration > 0) {
        const timeout = window.setTimeout(() => dismiss(id), duration);
        timeouts.current.set(id, timeout);
      }

      return id;
    },
    [dismiss, limit]
  );

  React.useEffect(
    () => () => {
      for (const timeout of timeouts.current.values()) window.clearTimeout(timeout);
      timeouts.current.clear();
    },
    []
  );
  React.useEffect(() => setMounted(true), []);

  const value = React.useMemo(() => ({ dismiss, toast, toasts }), [dismiss, toast, toasts]);
  const stack = (
    <ToastStack position={position}>
      {toasts.map(({ duration: _duration, id, ...toastProps }) => (
        <Toast key={id} {...toastProps} onDismiss={() => dismiss(id)} />
      ))}
    </ToastStack>
  );

  return (
    <ToastContext.Provider value={value}>
      {children}
      {mounted ? createPortal(stack, document.body) : null}
    </ToastContext.Provider>
  );
}

export function useToast() {
  const context = React.useContext(ToastContext);
  if (!context) {
    throw new Error("useToast must be used inside ToastProvider.");
  }
  return context;
}

type ClassValue = string | false | null | undefined;

export function cn(...values: ClassValue[]) {
  return values.filter(Boolean).join(" ");
}

@theme inline {
  --color-axie-ink: var(--axie-color-ink);
  --color-axie-paper: var(--axie-color-paper);
  --color-axie-surface: var(--axie-color-surface);
  --color-axie-surface-soft: var(--axie-color-surface-soft);
  --color-axie-muted: var(--axie-color-muted);
  --color-axie-line: var(--axie-color-line);
  --color-axie-accent: var(--axie-color-accent);
  --color-axie-accent-soft: var(--axie-color-accent-soft);
  --color-axie-danger: var(--axie-color-danger);
  --color-axie-danger-soft: var(--axie-color-danger-soft);
  --color-axie-warning: var(--axie-color-warning);
  --color-axie-warning-soft: var(--axie-color-warning-soft);
  --color-axie-info: var(--axie-color-info);
  --color-axie-info-soft: var(--axie-color-info-soft);
  --radius-axie-card: var(--axie-radius-card);
  --radius-axie-control: var(--axie-radius-control);
  --radius-axie-sheet: var(--axie-radius-sheet);
  --radius-axie-pill: var(--axie-radius-pill);
  --spacing-axie-page: var(--axie-space-page);
  --spacing-axie-xs: var(--axie-space-xs);
  --spacing-axie-sm: var(--axie-space-sm);
  --spacing-axie-md: var(--axie-space-md);
  --spacing-axie-lg: var(--axie-space-lg);
  --spacing-axie-xl: var(--axie-space-xl);
  --spacing-axie-2xl: var(--axie-space-2xl);
  --shadow-axie-raised: 0 16px 36px color-mix(in srgb, var(--axie-color-ink) 10%, transparent);
  --shadow-axie-soft: 0 10px 24px color-mix(in srgb, var(--axie-color-ink) 6%, transparent);
  --shadow-axie-nav: 0 16px 38px color-mix(in srgb, var(--axie-color-ink) 12%, transparent);
}

:root {
  --axie-color-ink: #263024;
  --axie-color-paper: #f4f1e6;
  --axie-color-surface: #fffdf4;
  --axie-color-surface-soft: #e8ead6;
  --axie-color-muted: #68705d;
  --axie-color-line: #d7d2b9;
  --axie-color-accent: #6f7f3f;
  --axie-color-accent-soft: #e0e8c7;
  --axie-color-danger: #a45447;
  --axie-color-danger-soft: #efd8d0;
  --axie-color-warning: #947236;
  --axie-color-warning-soft: #ecdcb8;
  --axie-color-info: #4d6972;
  --axie-color-info-soft: #dce8e6;
  --axie-radius-card: 10px;
  --axie-radius-control: 12px;
  --axie-radius-sheet: 30px;
  --axie-radius-pill: 999px;
  --axie-space-page: 20px;
  --axie-space-xs: 6px;
  --axie-space-sm: 10px;
  --axie-space-md: 14px;
  --axie-space-lg: 20px;
  --axie-space-xl: 28px;
  --axie-space-2xl: 36px;
  --axie-motion-fast: 160ms;
  --axie-motion-base: 240ms;
  --axie-motion-slow: 360ms;
  --axie-motion-ease: cubic-bezier(0.2, 0.9, 0.2, 1);
  --axie-motion-spring: cubic-bezier(0.16, 1, 0.3, 1);
  --axie-motion-pop: cubic-bezier(0.18, 1.24, 0.3, 1);
}

.axie-pressable {
  transform: translate3d(0, 0, 0) scale(1);
  transition-duration: var(--axie-motion-base);
  transition-property: background-color, border-color, box-shadow, color, opacity, transform;
  transition-timing-function: var(--axie-motion-spring);
  will-change: transform;
}

.axie-pressable:hover {
  transform: translate3d(0, -1px, 0) scale(1.005);
}

.axie-pressable:active {
  transform: translate3d(0, 0, 0) scale(0.985);
}

.axie-enter {
  animation: axie-enter var(--axie-motion-slow) var(--axie-motion-spring) both;
}

.axie-pop {
  animation: axie-pop var(--axie-motion-slow) var(--axie-motion-pop) both;
}

.axie-fade {
  animation: axie-fade var(--axie-motion-base) ease-out both;
}

.axie-sheet-backdrop {
  animation: axie-fade var(--axie-motion-fast) ease-out both;
}

.axie-sheet-panel {
  animation: axie-sheet-panel-in var(--axie-motion-slow) var(--axie-motion-ease) both;
}

.axie-row-enter {
  animation: axie-row-in var(--axie-motion-base) var(--axie-motion-ease) both;
  animation-delay: var(--axie-row-delay, 0ms);
}

.axie-slider {
  --axie-slider-fill: 0%;
  -webkit-appearance: none;
  appearance: none;
  block-size: 32px;
  inline-size: 100%;
  margin: 0;
  background: transparent;
  color: var(--axie-color-accent);
  cursor: pointer;
}

.axie-slider:disabled {
  cursor: not-allowed;
  opacity: 0.56;
}

.axie-slider::-webkit-slider-runnable-track {
  block-size: 12px;
  border: 1px solid color-mix(in srgb, var(--axie-color-line) 88%, var(--axie-color-ink));
  border-radius: var(--axie-radius-pill);
  background:
    linear-gradient(
      to right,
      var(--axie-color-accent) 0 var(--axie-slider-fill),
      color-mix(in srgb, var(--axie-color-surface-soft) 84%, var(--axie-color-paper)) var(--axie-slider-fill) 100%
    );
  box-shadow: inset 0 1px 0 color-mix(in srgb, var(--axie-color-surface) 74%, transparent);
  transition:
    background var(--axie-motion-base) var(--axie-motion-spring),
    border-color var(--axie-motion-base) var(--axie-motion-spring);
}

.axie-slider::-webkit-slider-thumb {
  -webkit-appearance: none;
  appearance: none;
  block-size: 22px;
  inline-size: 22px;
  margin-block-start: -6px;
  border: 2px solid var(--axie-color-surface);
  border-radius: 50%;
  background:
    radial-gradient(
      circle at 34% 32%,
      color-mix(in srgb, var(--axie-color-accent-soft) 62%, white) 0 22%,
      var(--axie-color-accent) 58%
    );
  box-shadow:
    0 2px 0 color-mix(in srgb, var(--axie-color-ink) 16%, transparent),
    0 10px 20px color-mix(in srgb, var(--axie-color-accent) 22%, transparent);
  transition:
    box-shadow var(--axie-motion-base) var(--axie-motion-spring),
    transform var(--axie-motion-base) var(--axie-motion-spring);
}

.axie-slider:hover::-webkit-slider-thumb {
  transform: scale(1.05);
}

.axie-slider:active::-webkit-slider-thumb {
  transform: scale(0.94);
}

.axie-slider:focus-visible::-webkit-slider-thumb {
  box-shadow:
    0 2px 0 color-mix(in srgb, var(--axie-color-ink) 16%, transparent),
    0 10px 20px color-mix(in srgb, var(--axie-color-accent) 22%, transparent),
    0 0 0 5px color-mix(in srgb, var(--axie-color-accent) 22%, transparent);
}

.axie-slider::-moz-range-track {
  block-size: 12px;
  border: 1px solid color-mix(in srgb, var(--axie-color-line) 88%, var(--axie-color-ink));
  border-radius: var(--axie-radius-pill);
  background: color-mix(in srgb, var(--axie-color-surface-soft) 84%, var(--axie-color-paper));
  box-shadow: inset 0 1px 0 color-mix(in srgb, var(--axie-color-surface) 74%, transparent);
}

.axie-slider::-moz-range-progress {
  block-size: 12px;
  border-radius: var(--axie-radius-pill);
  background: var(--axie-color-accent);
}

.axie-slider::-moz-range-thumb {
  box-sizing: border-box;
  block-size: 22px;
  inline-size: 22px;
  border: 2px solid var(--axie-color-surface);
  border-radius: 50%;
  background:
    radial-gradient(
      circle at 34% 32%,
      color-mix(in srgb, var(--axie-color-accent-soft) 62%, white) 0 22%,
      var(--axie-color-accent) 58%
    );
  box-shadow:
    0 2px 0 color-mix(in srgb, var(--axie-color-ink) 16%, transparent),
    0 10px 20px color-mix(in srgb, var(--axie-color-accent) 22%, transparent);
  transition:
    box-shadow var(--axie-motion-base) var(--axie-motion-spring),
    transform var(--axie-motion-base) var(--axie-motion-spring);
}

.axie-slider:hover::-moz-range-thumb {
  transform: scale(1.05);
}

.axie-slider:active::-moz-range-thumb {
  transform: scale(0.94);
}

.axie-slider:focus-visible::-moz-range-thumb {
  box-shadow:
    0 2px 0 color-mix(in srgb, var(--axie-color-ink) 16%, transparent),
    0 10px 20px color-mix(in srgb, var(--axie-color-accent) 22%, transparent),
    0 0 0 5px color-mix(in srgb, var(--axie-color-accent) 22%, transparent);
}

@keyframes axie-fade {
  from {
    opacity: 0;
  }
  to {
    opacity: 1;
  }
}

@keyframes axie-enter {
  from {
    opacity: 0;
    transform: translate3d(0, 10px, 0) scale(0.985);
  }
  to {
    opacity: 1;
    transform: translate3d(0, 0, 0) scale(1);
  }
}

@keyframes axie-pop {
  from {
    opacity: 0;
    transform: translate3d(0, 12px, 0) scale(0.96);
  }
  to {
    opacity: 1;
    transform: translate3d(0, 0, 0) scale(1);
  }
}

@keyframes axie-sheet-panel-in {
  from {
    opacity: 0.72;
    transform: translate3d(0, 26px, 0) scale(0.985);
  }
  to {
    opacity: 1;
    transform: translate3d(0, 0, 0) scale(1);
  }
}

@keyframes axie-row-in {
  from {
    opacity: 0;
    transform: translate3d(0, 8px, 0);
  }
  to {
    opacity: 1;
    transform: translate3d(0, 0, 0);
  }
}

@keyframes axie-accordion-down {
  from {
    opacity: 0;
    transform: translate3d(0, -4px, 0);
  }
  to {
    opacity: 1;
    transform: translate3d(0, 0, 0);
  }
}

@keyframes axie-shimmer {
  100% {
    transform: translateX(100%);
  }
}

@keyframes axie-pulse-dot {
  0%,
  100% {
    box-shadow: 0 0 0 0 color-mix(in srgb, var(--axie-color-accent) 30%, transparent);
  }
  50% {
    box-shadow: 0 0 0 5px color-mix(in srgb, var(--axie-color-accent) 0%, transparent);
  }
}

@media (prefers-reduced-motion: reduce) {
  *,
  *::before,
  *::after {
    animation-duration: 0.001ms !important;
    animation-iteration-count: 1 !important;
    scroll-behavior: auto !important;
    transition-duration: 0.001ms !important;
  }

  .axie-enter,
  .axie-pop,
  .axie-fade,
  .axie-sheet-backdrop,
  .axie-sheet-panel,
  .axie-row-enter {
    animation: none;
  }

  .axie-pressable,
  .axie-pressable:hover,
  .axie-pressable:active {
    transform: none;
  }
}
